/**
 * WordPress dependencies
 */
import { useEffect, useState } from "react";
import { __ } from "@wordpress/i18n";
import { useDispatch, useSelect, subscribe, select } from "@wordpress/data";
import {
	BlockControls,
	InspectorControls,
	useBlockProps,
	MediaUpload,
	MediaUploadCheck,
} from "@wordpress/block-editor";
import {
	__experimentalToggleGroupControl as ToggleGroupControl,
	__experimentalToggleGroupControlOption as ToggleGroupControlOption,
	__experimentalUnitControl as UnitControl,
	Button,
	ToolbarGroup,
	ToolbarButton,
	TextControl,
	PanelBody,
	RangeControl,
	ColorPalette,
} from "@wordpress/components";
import "./editor.scss";

/**
 * External dependencies
 */
import { ArrowRightLeft } from "lucide-react";

/**
 * Internal dependencies
 */
import { InspectorLabel } from "../libs/components/inspector-label";
import { isSVGFile } from "../libs/global";

/**
 * Block edit function
 */
export default function Edit({
	attributes: {
		imageId,
		imageUrl,
		imageName,
		imageContent,
		text,
		reversed,
		tabletReversed,
		mobileReversed,
		stacked,
		tabletStacked,
		mobileStacked,
		gap,
		tabletGap,
		mobileGap,
		imageWidth,
		imageHeight,
		svgColor,
		bindImageDimensions,
	},
	setAttributes,
	clientId,
}) {
	useEffect(() => {
		if (imageUrl && isSVGFile(imageUrl)) {
			fetch(imageUrl)
				.then((response) => response.text())
				.then((svgText) => {
					setAttributes({ imageContent: svgText });
				})
				.catch((error) => {
					console.error("Error fetching SVG:", error);
				});
		}
	}, [imageUrl]);

	const [layout, setLayout] = useState("desktop");
	// Get device type
	const deviceType = useSelect((select) => {
		const { getDeviceType } = select("core/editor");
		return getDeviceType()?.toLowerCase() || "desktop";
	}, []);
	// Update device type in block if it changes
	useEffect(() => {
		if (deviceType) {
			setLayout(deviceType.toLowerCase());
		}
	}, [deviceType]);

	// Set post and site editor device type
	const postEditorDispatch = useDispatch("core/editor");
	const siteEditorDispatch = useDispatch("core/edit-site");
	const setEditorDeviceType = (type) => {
		if (siteEditorDispatch?.__experimentalSetPreviewDeviceType) {
			siteEditorDispatch.__experimentalSetPreviewDeviceType(type);
		} else if (postEditorDispatch?.setDeviceType) {
			postEditorDispatch.setDeviceType(type);
		}
	};
	const innerBlockCount = useSelect(
		(select) => select("core/block-editor").getBlocks(clientId).length,
		[clientId],
	);

	const classNames = [];
	if (innerBlockCount == 1) {
		classNames.push("block-booster-icon-and-text--single-child");
	}

	if (reversed) {
		classNames.push("block-booster-icon-and-text--is-reversed");
	}
	if (tabletReversed) {
		classNames.push("block-booster-icon-and-text--tablet-is-reversed");
	}
	if (mobileReversed) {
		classNames.push("block-booster-icon-and-text--mobile-is-reversed");
	}
	if (stacked) {
		classNames.push("block-booster-icon-and-text--is-stacked");
	}
	if (tabletStacked) {
		classNames.push("block-booster-icon-and-text--tablet-is-stacked");
	}
	if (mobileStacked) {
		classNames.push("block-booster-icon-and-text--mobile-is-stacked");
	}
	const blockProps = useBlockProps({
		className: classNames.join(" "),
		style: {
			gap:
				layout == "desktop" ? gap : layout == "tablet" ? tabletGap : mobileGap,
		},
	});

	const onImageSelect = (media) => {
		if (!media || !media.url) {
			setAttributes({ imageId: 0, imageUrl: "", imageName: "" });
			return;
		}
		setAttributes({
			imageId: media.id,
			imageUrl: media.url,
			imageName: media.title || media.filename, // Use title or filename
		});
	};
	const removeImage = () => {
		setAttributes({ imageId: 0, imageUrl: "", imageName: "" });
	};

	// Handler for width/height change with binding
	const handleWidthChange = (value) => {
		console.log("value", value);

		if (bindImageDimensions) {
			setAttributes({ imageWidth: value, imageHeight: value });
		} else {
			setAttributes({ imageWidth: value });
		}
	};

	const handleHeightChange = (value) => {
		if (bindImageDimensions) {
			setAttributes({ imageWidth: value, imageHeight: value });
		} else {
			setAttributes({ imageHeight: value });
		}
	};
	console.log("imageWidth", imageWidth);

	const ArrowRightLeftIcon = (
		<ArrowRightLeft fill="white" className="svg-no-fill" />
	);
	const units = [
		{ value: "px", label: "px", default: 0 },
		{ value: "%", label: "%", default: 10 },
		{ value: "em", label: "em", default: 0 },
	];
	return (
		<>
			<BlockControls>
				<ToolbarGroup>
					<ToolbarButton
						label={__("Reverse", "block-booster")}
						icon={ArrowRightLeftIcon}
						isPressed={reversed}
						onClick={() => {
							setAttributes({ reversed: !reversed });
						}}
					/>
				</ToolbarGroup>
			</BlockControls>
			<InspectorControls>
				<PanelBody title={__("Settings", "block-booster")}>
					<div
						style={{
							display: "flex",
							alignItems: "flex-end",
							justifyContent: "space-between",
							gap: "10px",
							marginBottom: "10px",
						}}
					>
						<UnitControl
							__next40pxDefaultSize
							units={units}
							label={__("Width", "block-booster")}
							value={imageWidth}
							onChange={handleWidthChange}
							min={0}
							className="block-booster-unit-control-no-margin"
							style={{ flex: 1, margin: 0 }}
						/>
						<UnitControl
							__next40pxDefaultSize
							units={units}
							label={__("Height", "block-booster")}
							value={imageHeight}
							onChange={handleHeightChange}
							min={0}
							className="block-booster-unit-control-no-margin"
							style={{ flex: 1, margin: 0 }}
						/>
					</div>
					<label
						style={{
							display: "flex",
							alignItems: "center",
							fontSize: "12px",
							marginBottom: "15px",
						}}
					>
						<input
							type="checkbox"
							checked={bindImageDimensions}
							onChange={(e) =>
								setAttributes({ bindImageDimensions: e.target.checked })
							}
							style={{ marginRight: "5px" }}
						/>
						{__("Link dimensions", "block-booster")}
					</label>
					<TextControl
						__nextHasNoMarginBottom
						__next40pxDefaultSize
						label={__("Add text", "block-booster")}
						value={text}
						onChange={(value) =>
							setAttributes({
								text: value,
							})
						}
					/>
					<InspectorLabel
						title={__("Gap", "block-booster")}
						defaultValue={layout}
						onChange={(value) => {
							setLayout(value);
							setEditorDeviceType(
								value == "desktop"
									? "Desktop"
									: value == "tablet"
									? "Tablet"
									: "Mobile",
							);
						}}
					/>
					{layout == "desktop" ? (
						<RangeControl
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							value={gap}
							label={null}
							onChange={(value) =>
								setAttributes({
									gap: value,
								})
							}
							min={0}
							max={100}
						/>
					) : layout == "tablet" ? (
						<RangeControl
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							value={tabletGap}
							label={null}
							onChange={(value) =>
								setAttributes({
									tabletGap: value,
								})
							}
							min={0}
							max={100}
						/>
					) : (
						<RangeControl
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							value={mobileGap}
							label={null}
							onChange={(value) =>
								setAttributes({
									mobileGap: value,
								})
							}
							min={0}
							max={100}
						/>
					)}
					<InspectorLabel
						title={__("Reverse", "block-booster")}
						defaultValue={layout}
						onChange={(value) => {
							setLayout(value);
							setEditorDeviceType(
								value == "desktop"
									? "Desktop"
									: value == "tablet"
									? "Tablet"
									: "Mobile",
							);
						}}
					/>
					{layout == "desktop" ? (
						<ToggleGroupControl
							value={reversed}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ reversed: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					) : layout == "tablet" ? (
						<ToggleGroupControl
							value={tabletReversed}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ tabletReversed: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					) : (
						<ToggleGroupControl
							value={mobileReversed}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ mobileReversed: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					)}
					<InspectorLabel
						title={__("Stacked", "block-booster")}
						defaultValue={layout}
						onChange={(value) => {
							setLayout(value);
							setEditorDeviceType(
								value == "desktop"
									? "Desktop"
									: value == "tablet"
									? "Tablet"
									: "Mobile",
							);
						}}
					/>
					{layout == "desktop" ? (
						<ToggleGroupControl
							value={stacked}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ stacked: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					) : layout == "tablet" ? (
						<ToggleGroupControl
							value={tabletStacked}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ tabletStacked: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					) : (
						<ToggleGroupControl
							value={mobileStacked}
							isBlock={true}
							__nextHasNoMarginBottom
							__next40pxDefaultSize
							onChange={(value) => setAttributes({ mobileStacked: value })}
						>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={true}
								label={__("Enabled", "block-booster")}
							/>
							<ToggleGroupControlOption
								isAdaptiveWidth={true}
								value={false}
								label={__("Disabled", "block-booster")}
							/>
						</ToggleGroupControl>
					)}
					<MediaUploadCheck>
						<MediaUpload
							allowedTypes={["image"]}
							multiple={false}
							value={imageId}
							onSelect={onImageSelect}
							render={({ open }) => (
								<div
									style={{
										display: "flex",
										flexDirection: "column",
										justifyContent: "center",
										alignItems: "center",
										width: "100%",
									}}
								>
									{imageUrl ? (
										<>
											<img
												src={imageUrl}
												alt={imageName}
												style={{ width: "150px" }}
											/>
											<Button
												isDestructive
												variant="secondary"
												onClick={removeImage}
											>
												{__("Remove Image", "block-booster")}
											</Button>
										</>
									) : (
										<div
											style={{
												display: "flex",
												flexDirection: "column",
												justifyContent: "center",
												alignItems: "center",
												width: "100%",
											}}
										>
											<Button variant="primary" onClick={open}>
												{__("Upload or Select Image", "block-booster")}
											</Button>
										</div>
									)}
								</div>
							)}
						/>
					</MediaUploadCheck>
					<div style={{ marginTop: "10px", marginBottom: "10px" }}>
						<InspectorLabel
							title={__("SVG color", "block-booster")}
							hideLayoutButton={true}
						/>
					</div>
					<ColorPalette
						asButtons={true}
						clearable={true}
						width="100%"
						value={svgColor}
						onChange={(color) => setAttributes({ svgColor: color })}
					/>
				</PanelBody>
			</InspectorControls>
			<div {...blockProps}>
				{imageUrl &&
					(isSVGFile(imageUrl) ? (
						<div className="block-booster-icon-and-text--left">
							<span
								style={{
									color: svgColor,
									width: `${imageWidth}`,
									height: `${imageHeight}`,
									display: "inline-block",
								}}
								dangerouslySetInnerHTML={{ __html: imageContent }}
							></span>
						</div>
					) : (
						<div className="block-booster-icon-and-text--left">
							<img
								style={{ width: `${imageWidth}`, height: `${imageHeight}` }}
								src={imageUrl}
								alt={imageName}
							/>
						</div>
					))}
				<div className="block-booster-icon-and-text--right">{text}</div>
			</div>
		</>
	);
}
